1	const PROCESSING_FEE = 5;
2	const BLOCK_SIZE = 3;
3	const BLOCK_PRICE = 60;
4	const COMPONENT_BASE = 25;
5	const FIRST_INS_SURCHARGE = 0.1;
6	const CURSE_SURCHARGE = 0.5;
7	const HIGH_ENCH_SURCHARGE = 0.3;
8	const HIGH_ENCH_THRESHOLD = 5;
9	const LOYALTY_DISCOUNT = 0.2;
10	const LOYALTY_THRESHOLD = 2;
11	const FOLLOW_UP_DISCOUNT = 0.15;
12	
13	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	  rune: 25,
19	  moonstone: 25,
20	};
21	
22	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
23	
24	type Item = {
25	  type: string;
26	  enchantment?: number;
27	  cursed?: boolean;
28	  material?: string;
29	};
30	
31	const baseForItem = (item: Item): number =>
32	  BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0;
33	
34	const isComponent = (item: Item): boolean =>
35	  COMPONENT_TYPES.has(item.type);
36	
37	const itemModifierSum = (item: Item): number => {
38	  let mod = FIRST_INS_SURCHARGE;
39	  if (item.cursed) mod += CURSE_SURCHARGE;
40	  if ((item.enchantment ?? 0) >= HIGH_ENCH_THRESHOLD) mod += HIGH_ENCH_SURCHARGE;
41	  return mod;
42	};
43	
44	const itemCharge = (item: Item): number =>
45	  baseForItem(item) * (1 + itemModifierSum(item));
46	
47	const countByType = (items: Item[]): Record<string, number> => {
48	  const counts: Record<string, number> = {};
49	  for (const item of items) {
50	    counts[item.type] = (counts[item.type] ?? 0) + 1;
51	  }
52	  return counts;
53	};
54	
55	const componentsCharge = (items: Item[]): number => {
56	  const componentItems = items.filter(isComponent);
57	  const counts = countByType(componentItems);
58	  let total = 0;
59	  for (const type in counts) {
60	    const count = counts[type];
61	    if (count === BLOCK_SIZE) {
62	      total += BLOCK_PRICE * (1 + FIRST_INS_SURCHARGE);
63	    } else {
64	      total += count * COMPONENT_BASE * (1 + FIRST_INS_SURCHARGE);
65	    }
66	  }
67	  return total;
68	};
69	
70	const componentsBase = (items: Item[]): number => {
71	  const componentItems = items.filter(isComponent);
72	  const counts = countByType(componentItems);
73	  let total = 0;
74	  for (const type in counts) {
75	    const count = counts[type];
76	    total += count === BLOCK_SIZE ? BLOCK_PRICE : count * COMPONENT_BASE;
77	  }
78	  return total;
79	};
80	
81	const nonComponentsCharge = (items: Item[]): number =>
82	  items.filter((item) => !isComponent(item)).reduce((sum, item) => sum + itemCharge(item), 0);
83	
84	const nonComponentsBase = (items: Item[]): number =>
85	  items.filter((item) => !isComponent(item)).reduce((sum, item) => sum + baseForItem(item), 0);
86	
87	export function quote(input: any): unknown {
88	  const items: Item[] = input.items;
89	  const itemTotal = nonComponentsCharge(items) + componentsCharge(items);
90	  const policyBase = nonComponentsBase(items) + componentsBase(items);
91	  const years = input.customer?.yearsWithMHPCO ?? 0;
92	  let policyModifiers = 0;
93	  if (years >= LOYALTY_THRESHOLD) policyModifiers -= LOYALTY_DISCOUNT;
94	  if (input.isFollowUp) policyModifiers -= FOLLOW_UP_DISCOUNT;
95	  const policyAdjustment = policyBase * policyModifiers;
96	  const raw = itemTotal + policyAdjustment + PROCESSING_FEE;
97	  const premium = Math.ceil(Math.round(raw * 1e8) / 1e8);
98	  return { premium };
99	}
