102	  let payout = 0;
103	  for (const damageEntry of input.incident.damages) {
104	    const item = input.policy.items.find((i: Item) => i.type === damageEntry.itemType);
105	    let amount = damageEntry.amount;
106	    if (item && (item.enchantment ?? 0) >= 8) {
107	      amount = amount * 0.5;
108	    }
109	    payout += amount - 100;
110	  }
111	  const remainingCap = input.policy.remainingCap - payout;
112	  return { payout, remainingCap };
