export function claim(input: any): unknown {
  let payout = 0;
  for (const damageEntry of input.incident.damages) {
    const item = input.policy.items.find((i: Item) => i.type === damageEntry.itemType);
    let amount = damageEntry.amount;
    if (item && (item.enchantment ?? 0) >= 8) {
      amount = amount * 0.5;
    }
    payout += amount - 100;
  }
  payout = Math.min(payout, input.policy.remainingCap);
  const remainingCap = input.policy.remainingCap - payout;
  return { payout, remainingCap };
}
